"use strict";(self.webpackChunksite=self.webpackChunksite||[]).push([[5604],{1933:e=>{e.exports=JSON.parse('{"lang":"en","resources":{"landing":{"meta":{"title":"Linguist - Translate Web Pages Privately | Browser Translator Extension for Chrome & Firefox","description":"Privacy\u2011first browser translator extension for Chrome and Firefox. Translate web pages, selected text, subtitles and messages instantly. Works offline and supports translation service integrations and APIs."},"navigation":{"features":{"content":"Features"},"blog":{"content":"Blog"},"docs":{"content":"Docs"},"github":{"content":"GitHub"}},"install":{"chrome":"Install for Chrome","firefox":"Install for Firefox"},"sections":{"hero":{"title":"Translate web pages fluently","description":"Linguist is a flexible browser translator powered by the most popular translation services.\\n\\nTranslate entire web pages, selected text, subtitles on Netflix or in video calls, and private messages. Listen to translations and save important ones to your personal dictionary to learn new words, even offline.\\n\\nLinguist is a modern, privacy\u2011first alternative to Google Translate browser extensions. Try it for free."},"opensource":{"title":"Open source","content":"Linguist is a free and <0>open\u2011source</0> browser translation extension. It does not collect or sell user data.\\n\\nYou can <1>donate</1> to support Linguist and help us maintain independence and high quality.\\n\\nShare Linguist on social media to help others discover it."},"support":{"title":"Support","content":"If you have questions, contact us <0/>.\\nIf you found a bug and have a GitHub account, please <1>create an issue</1>."},"createdBy":{"content":"Created by <0/>."}},"features":{"title":"Features","items":{"offlineTranslation":{"title":"Offline translation and privacy","content":"Translate text directly on your device with the built\u2011in offline translator. Your text stays private and is not sent over the internet.\\n\\nEnable this feature in the options page to keep translations private when working with emails, documents, or personal messages.\\n\\nThe offline translator also allows you to translate pages without an internet connection, which is especially useful while traveling."},"fullPageTranslation":{"title":"Translate entire web pages","content":"Fast, high\u2011quality full\u2011page translation in just a few clicks.\\n\\nUse a hotkey to translate instantly. Hover over translated text to see the original. Translate even private pages behind login forms or paywalls.\\n\\nSet up automatic translation rules based on page language or domain.\\n\\nLinguist follows a minimal page\u2011modification approach: it changes only text nodes and preserves the page layout and user experience.\\n\\nEnable real\u2011time translation for cross\u2011language meetings on Zoom, Google Meet, and Microsoft Teams."},"selectedTextTranslation":{"title":"Translate selected text on any website","content":"Encounter unfamiliar words while reading an online article?\\nSimply select text on the page and click the translate button.\\n\\nListen to both the original and translated text, and save translations to your dictionary to review later."},"textTranslation":{"title":"Quick text translation","content":"Need to translate something quickly? Click the Linguist icon and enter your text.\\n\\nNo need to switch between tabs or open translation websites. Translate directly in your browser using the service you prefer."},"knowledgeBase":{"title":"Build your personal knowledge base","content":"Every translation is saved in your history, and you can add important entries to your personal dictionary. Search your dictionary and translation history anytime.\\n\\nNothing is lost, even during long research or learning sessions.\\n\\nThe dictionary works offline, making Linguist ideal for language learners and travelers who need constant access to their word lists."},"customTranslators":{"title":"Integrate Translation Services and APIs","content":"Linguist lets you choose which translation service to use.\\n\\nIt supports popular translation providers such as Google, Yandex, and Microsoft, with more than 100 languages available.\\n\\nIf a service you need is not included, you can add it as a <0>custom translator</0>.\\n\\nCustom translators allow you to integrate any translation system \u2014 from modern LLM services such as ChatGPT, DeepL, DeepSeek, and Gemini to local translators running on your device, such as Ollama or LibreTranslate."}}},"faq":{"title":"FAQ","items":{"whatIsLinguist":{"title":"What is Linguist?","content":"Linguist is a privacy\u2011first browser translation extension for Chrome and Firefox.\\n\\nIt lets you translate full web pages, selected text, subtitles, and messages directly in your browser without switching to external translation websites."},"whyLinguist":{"title":"Why use Linguist?","content":"There are many browser extensions that translate web pages, and some browsers even include built\u2011in translators. So why use Linguist?\\n\\nMost built\u2011in translators and translation extensions are limited in flexibility. Many rely on a single translation provider such as Google Translate or Microsoft Bing, while Firefox offers its own offline translator. In most cases, you cannot choose the service that best fits your needs.\\n\\nIf the translation quality is not good enough for your use case, or if sending private text to third\u2011party services is not acceptable, many tools leave you without a good alternative.\\n\\nMany tools also focus on only one task. Some translate full pages, while others translate only selected text.\\n\\nAt the same time, some translation extensions are built primarily around monetization. Features such as translation history or personal dictionaries may require a subscription, and sometimes even basic features like a dark theme are treated as premium options.\\n\\nLinguist takes a different approach. It is designed as a practical translation tool. You can choose the translation service that works best for you, switch between providers, or add your own custom translators.\\n\\nLinguist also brings everything together in one place: translate entire web pages, selected text, subtitles, and messages while keeping track of important translations in your history and personal dictionary."},"theLinguistLogo":{"title":"Why is the Linguist logo the Tower of Babel?","content":"The Linguist logo is inspired by the <wiki>Tower of Babel</wiki>, one of the oldest stories about language and communication.\\n\\nAccording to the story, people once spoke the same language and tried to build a tower reaching the sky. The tower was never completed, and humanity was scattered across many languages. Since then, language differences have often made communication more difficult.\\n\\nLinguist was created to help solve this problem.\\n\\nThe Tower of Babel in the logo is a reminder of that story: many languages, many cultures, and the constant human effort to understand one another. Linguist helps bridge those gaps by making translation simple, flexible, and accessible directly in your browser.\\n\\nThe logo also reflects the spirit of the project. Linguist is not just another wrapper around \\"Google Translate\\". It is built by people who care about languages, privacy, and open technology. The Tower of Babel represents curiosity, learning, and the idea that language differences should bring people together rather than keep them apart."},"imageTranslation":{"title":"Why doesn\u2019t Linguist translate text in images?","content":"Linguist focuses on reliable and high\u2011quality translation features.\\n\\nWe have researched different approaches to translating text inside images. At the moment, most available solutions do not provide consistent results, especially when running directly in the browser \u2014 which is important for maintaining user privacy.\\n\\nBecause of this, Linguist does not currently include image translation. We prefer not to ship features that do not meet our quality standards.\\n\\nIf we find a reliable and privacy\u2011respecting way to implement image translation in the future, we would be happy to add it."},"howTranslatePages":{"title":"How does Linguist translate web pages?","content":"Linguist can translate entire web pages in just a few clicks. You can start page translation using the extension button or a keyboard shortcut.\\n\\nThe original text always remains accessible. Hover over translated text to see the original."},"offlineTranslation":{"title":"Can Linguist translate pages offline?","content":"Yes. Linguist includes a built\u2011in offline translator that allows you to translate text without sending data over the internet.\\n\\nThis helps protect your privacy and allows you to translate content even without an internet connection."},"privacy":{"title":"Is Linguist private?","content":"Yes. Linguist is designed with privacy in mind.\\n\\nThe extension does not collect or sell user data. When using the <offline-translator>offline translator</offline-translator>, translations are processed entirely on your device."},"supportedBrowsers":{"title":"Which browsers does Linguist support?","content":"Linguist is available for Chrome and Firefox. It also works in other Chromium\u2011based browsers that support Chrome extensions.\\n\\nLinguist also works in Android browsers that support extensions, such as Firefox for Android and some Chromium\u2011based browsers."},"selectedText":{"title":"Can Linguist translate selected text?","content":"Yes. Simply select text on any web page and use the translate button to translate it instantly.\\n\\nYou can also listen to the translation and save it to your personal dictionary."},"customTranslators":{"title":"Can I use my own translation service?","content":"Yes. Linguist supports <custom-translator>custom translators</custom-translator>, which allow you to integrate additional translation services.\\n\\nYou can connect external APIs or local translation systems such as <libre-translate>LibreTranslate</libre-translate> or <ollama>Ollama</ollama>."},"isFree":{"title":"Is Linguist free?","content":"Yes. Linguist is completely free and <linguist>open source</linguist>.\\n\\nThe project is supported by the community, and you can optionally <donations>support it with a donation</donations>."}}}}},"altVersions":[{"langCode":"ar","langName":"\u0627\u0644\u0639\u0631\u0628\u064a\u0629","url":"https://linguister.io/ar"},{"langCode":"bg","langName":"\u0431\u044a\u043b\u0433\u0430\u0440\u0441\u043a\u0438","url":"https://linguister.io/bg"},{"langCode":"bn","langName":"\u09ac\u09be\u0982\u09b2\u09be","url":"https://linguister.io/bn"},{"langCode":"ca","langName":"catal\xe0","url":"https://linguister.io/ca"},{"langCode":"cs","langName":"\u010de\u0161tina","url":"https://linguister.io/cs"},{"langCode":"da","langName":"dansk","url":"https://linguister.io/da"},{"langCode":"de","langName":"Deutsch","url":"https://linguister.io/de"},{"langCode":"el","langName":"\u0395\u03bb\u03bb\u03b7\u03bd\u03b9\u03ba\u03ac","url":"https://linguister.io/el"},{"langCode":"en","langName":"English","url":"https://linguister.io/"},{"langCode":"es","langName":"espa\xf1ol","url":"https://linguister.io/es"},{"langCode":"fa","langName":"\u0641\u0627\u0631\u0633\u06cc","url":"https://linguister.io/fa"},{"langCode":"fi","langName":"suomi","url":"https://linguister.io/fi"},{"langCode":"fr","langName":"fran\xe7ais","url":"https://linguister.io/fr"},{"langCode":"gu","langName":"\u0a97\u0ac1\u0a9c\u0ab0\u0abe\u0aa4\u0ac0","url":"https://linguister.io/gu"},{"langCode":"he","langName":"\u05e2\u05d1\u05e8\u05d9\u05ea","url":"https://linguister.io/he"},{"langCode":"hi","langName":"\u0939\u093f\u0928\u094d\u0926\u0940","url":"https://linguister.io/hi"},{"langCode":"hu","langName":"magyar","url":"https://linguister.io/hu"},{"langCode":"id","langName":"Indonesia","url":"https://linguister.io/id"},{"langCode":"it","langName":"italiano","url":"https://linguister.io/it"},{"langCode":"ja","langName":"\u65e5\u672c\u8a9e","url":"https://linguister.io/ja"},{"langCode":"jv","langName":"Jawa","url":"https://linguister.io/jv"},{"langCode":"ka","langName":"\u10e5\u10d0\u10e0\u10d7\u10e3\u10da\u10d8","url":"https://linguister.io/ka"},{"langCode":"ko","langName":"\ud55c\uad6d\uc5b4","url":"https://linguister.io/ko"},{"langCode":"mr","langName":"\u092e\u0930\u093e\u0920\u0940","url":"https://linguister.io/mr"},{"langCode":"nb","langName":"norsk bokm\xe5l","url":"https://linguister.io/nb"},{"langCode":"nl","langName":"Nederlands","url":"https://linguister.io/nl"},{"langCode":"pa","langName":"\u0a2a\u0a70\u0a1c\u0a3e\u0a2c\u0a40","url":"https://linguister.io/pa"},{"langCode":"pl","langName":"polski","url":"https://linguister.io/pl"},{"langCode":"pt-BR","langName":"portugu\xeas (Brasil)","url":"https://linguister.io/pt-BR"},{"langCode":"pt-PT","langName":"portugu\xeas europeu","url":"https://linguister.io/pt-PT"},{"langCode":"ro","langName":"rom\xe2n\u0103","url":"https://linguister.io/ro"},{"langCode":"ru","langName":"\u0440\u0443\u0441\u0441\u043a\u0438\u0439","url":"https://linguister.io/ru"},{"langCode":"sl","langName":"sloven\u0161\u010dina","url":"https://linguister.io/sl"},{"langCode":"sr","langName":"\u0441\u0440\u043f\u0441\u043a\u0438","url":"https://linguister.io/sr"},{"langCode":"sv","langName":"svenska","url":"https://linguister.io/sv"},{"langCode":"ta","langName":"\u0ba4\u0bae\u0bbf\u0bb4\u0bcd","url":"https://linguister.io/ta"},{"langCode":"te","langName":"\u0c24\u0c46\u0c32\u0c41\u0c17\u0c41","url":"https://linguister.io/te"},{"langCode":"th","langName":"\u0e44\u0e17\u0e22","url":"https://linguister.io/th"},{"langCode":"tr","langName":"T\xfcrk\xe7e","url":"https://linguister.io/tr"},{"langCode":"uk","langName":"\u0443\u043a\u0440\u0430\u0457\u043d\u0441\u044c\u043a\u0430","url":"https://linguister.io/uk"},{"langCode":"ur","langName":"\u0627\u0631\u062f\u0648","url":"https://linguister.io/ur"},{"langCode":"vi","langName":"Ti\u1ebfng Vi\u1ec7t","url":"https://linguister.io/vi"},{"langCode":"zh-CN","langName":"\u4e2d\u6587\uff08\u4e2d\u56fd\uff09","url":"https://linguister.io/zh-CN"},{"langCode":"zh-TW","langName":"\u4e2d\u6587\uff08\u53f0\u7063\uff09","url":"https://linguister.io/zh-TW"}]}')}}]);